import { task } from "@trigger.dev/sdk/v3";

export const subTask = task({
  id: "sub-task-1-1",
  run: async () => {
    return { success: true };
  },
});

export const parentTask = task({
  id: "parent-task-1",
  run: async (payload: any) => {
    const result = await subTask.triggerAndWait(payload);
    return { subTaskResult: result.unwrap() };
  },
});

